// src/pages/RegisterManageSub1Page.js
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import * as XLSX from 'xlsx'; // Import thư viện xlsx để xuất Excel

import './RegisterManageSub1Page.css'; // Import file CSS riêng cho trang này

/**
 * Component RegisterManageSub1Page hiển thị danh sách các cơ sở kinh doanh, chế biến gỗ,
 * cho phép tìm kiếm, lọc, ẩn/hiện cột và phân trang.
 */
function RegisterManageSub1Page() { // ĐỔI TÊN COMPONENT TỪ FarmListPage
  // State để lưu trữ danh sách các cơ sở được tải về từ API (giờ là cơ sở gỗ)
  const [woods, setWoods] = useState([]); // ĐỔI TÊN STATE TỪ farms
  // State cho bộ lọc tìm kiếm chung (theo tên, địa chỉ, người đại diện, v.v.)
  const [filter, setFilter] = useState('');
  // State cho bộ lọc Tỉnh (Thành phố)
  const [selectedProvince, setSelectedProvince] = useState('');
  // State cho bộ lọc Xã (Phường)
  const [selectedCommune, setSelectedCommune] = useState('');
  // State cho bộ lọc Loài (Giờ có thể là Loại gỗ hoặc Loại hình kinh doanh gỗ)
  const [selectedSpecies, setSelectedSpecies] = useState(''); // Có thể là loại gỗ
  // State cho bộ lọc Loại cơ sở đăng ký (Đảm bảo chỉ lọc cơ sở kinh doanh, chế biến gỗ)
  const [selectedLoaiCoSoDangKy, setSelectedLoaiCoSoDangKy] = useState('Đăng ký cơ sở kinh doanh, chế biến gỗ');
  // State cho bộ lọc Ngành nghề kinh doanh gỗ
  const [selectedNganhNgheKinhDoanhGo, setSelectedNganhNgheKinhDoanhGo] = useState('');
  // State cho bộ lọc Trạng thái
  const [selectedTrangThai, setSelectedTrangThai] = useState('');

  // State để lưu trữ các giá trị Tỉnh (Thành phố) duy nhất cho dropdown
  const [uniqueProvinces, setUniqueProvinces] = useState([]);
  // State để lưu trữ các giá trị Xã (Phường) duy nhất cho dropdown
  const [uniqueCommunes, setUniqueCommunes] = useState([]);
  // State để lưu trữ các giá trị Loài duy nhất cho dropdown (giờ là Loại gỗ)
  const [uniqueSpecies, setUniqueSpecies] = useState([]);
  // State để lưu trữ các giá trị Loại cơ sở đăng ký duy nhất cho dropdown
  const [uniqueLoaiCoSoDangKy, setUniqueLoaiCoSoDangKy] = useState([]);
  // State để lưu trữ các giá trị Ngành nghề kinh doanh gỗ duy nhất cho dropdown
  const [uniqueNganhNgheKinhDoanhGo, setUniqueNganhNgheKinhDoanhGo] = useState([]);
  // State để lưu trữ các giá trị Trạng thái duy nhất cho dropdown
  const [uniqueTrangThai, setUniqueTrangThai] = useState([]);

  // Hook để điều hướng trang
  const navigate = useNavigate();
  // Lấy token xác thực từ localStorage
  const token = localStorage.getItem('token');

  // Định nghĩa cấu hình các cột của bảng, bao gồm ID, nhãn hiển thị, trạng thái hiển thị ban đầu, và chiều rộng tối thiểu
  // GIỮ LẠI TẤT CẢ CÁC TRƯỜNG NHƯ ĐÃ YÊU CẦU
  const initialColumnsConfig = {
    // Thông tin cơ sở
	tinhThanhPho: { id: 'tinhThanhPho', label: 'Tỉnh (TP)', visible: true, minWidth: '100px' },
	xaPhuong: { id: 'xaPhuong', label: 'Xã (Phường)', visible: true, minWidth: '100px' },
    diaChiCoSo: { id: 'diaChiCoSo', label: 'Địa chỉ cơ sở', visible: true, minWidth: '220px' },
    tenCoSo: { id: 'tenCoSo', label: 'Tên cơ sở', visible: true, minWidth: '180px' },

    vido: { id: 'vido', label: 'Vĩ độ', visible: true, minWidth: '80px' },
    kinhdo: { id: 'kinhdo', label: 'Kinh độ', visible: true, minWidth: '80px' },
    // loaiHinhCoSo: { id: 'loaiHinhCoSo', label: 'Loại hình cơ sở', visible: true, minWidth: '120px' }, // Removed
    ngayThanhLap: { id: 'ngayThanhLap', label: 'Ngày thành lập', visible: true, minWidth: '100px' },
    giayPhepKinhDoanh: { id: 'giayPhepKinhDoanh', label: 'Số GPKD', visible: true, minWidth: '100px' },

    // Thông tin người đại diện
    tenNguoiDaiDien: { id: 'tenNguoiDaiDien', label: 'Người đại diện', visible: true, minWidth: '150px' },
    namSinh: { id: 'namSinh', label: 'Năm sinh', visible: true, minWidth: '80px' },
    soCCCD: { id: 'soCCCD', label: 'Số CCCD/Hộ chiếu', visible: true, minWidth: '120px' },
    ngayCapCCCD: { id: 'ngayCapCCCD', label: 'Ngày cấp CCCD', visible: true, minWidth: '100px' },
    noiCapCCCD: { id: 'noiCapCCCD', label: 'Nơi cấp CCCD', visible: true, minWidth: '120px' },
    soDienThoaiNguoiDaiDien: { id: 'soDienThoaiNguoiDaiDien', label: 'SĐT Người đại diện', visible: true, minWidth: '120px' },
    diaChiNguoiDaiDien: { id: 'diaChiNguoiDaiDien', label: 'Địa chỉ Người đại diện', visible: true, minWidth: '180px' },
    // emailNguoiDaiDien: { id: 'emailNguoiDaiDien', label: 'Email Người đại diện', visible: true, minWidth: '180px' }, // Removed


    // Thông tin cơ sở kinh doanh & chế biến gỗ
    loaiHinhKinhDoanhGo: { id: 'loaiHinhKinhDoanhGo', label: 'Loại hình KD gỗ', visible: false, minWidth: '120px' },
    nganhNgheKinhDoanhGo: { id: 'nganhNgheKinhDoanhGo', label: 'Ngành nghề KD gỗ', visible: false, minWidth: '120px' },
    khoiLuong: { id: 'khoiLuong', label: 'Khối lượng', visible: true, minWidth: '80px' }, // Nếu là tổng khối lượng trong cơ sở
    tenLamSan: { id: 'tenLamSan', label: 'Tên lâm sản', visible: true, minWidth: '150px' }, // Nếu là một loại lâm sản chính
    tenKhoaHoc: { id: 'tenKhoaHoc', label: 'Tên khoa học', visible: true, minWidth: '180px' }, // Tên khoa học của lâm sản

    // Các trường chung khác
    trangThai: { id: 'trangThai', label: 'Trạng thái', visible: true, minWidth: '100px' },

    ghiChu: { id: 'ghiChu', label: 'Ghi chú', visible: false, minWidth: '200px' },

    // Cột hành động (chiều rộng cố định)
    actions: { id: 'actions', label: '🛠️', visible: true, width: '175px', minWidth: '175px', maxWidth: '175px' },
  };

  // State để quản lý trạng thái hiển thị của các cột
  const [columns, setColumns] = useState(initialColumnsConfig);
  // State để quản lý trạng thái hiển thị của bảng tùy chọn cột
  const [showColumnOptions, setShowColumnOptions] = useState(false);

  // Các state liên quan đến phân trang
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(15); // Mặc định 15 mục mỗi trang

  /**
   * useEffect để tải trạng thái hiển thị cột từ localStorage khi component được mount.
   * Điều này giúp duy trì lựa chọn của người dùng giữa các lần truy cập.
   */
  useEffect(() => {
    try {
      const savedColumns = localStorage.getItem('tableColumnsVisibility_WoodBusiness'); // ĐỔI KEY LOCALSTORAGE ĐỂ TRÁNH XUNG ĐỘT VỚI TRANG KHÁC
      if (savedColumns) {
        const parsedSavedColumns = JSON.parse(savedColumns);
        // Hợp nhất cấu hình đã lưu với cấu hình ban đầu để xử lý các cột mới/bị xóa
        const mergedColumns = Object.keys(initialColumnsConfig).reduce((acc, key) => {
          const savedCol = parsedSavedColumns.find(sCol => sCol.id === key);
          // Hợp nhất trạng thái hiển thị đã lưu, nhưng vẫn giữ các thuộc tính ban đầu
          acc[key] = savedCol ? { ...initialColumnsConfig[key], visible: savedCol.visible } : initialColumnsConfig[key];
          return acc;
        }, {});
        setColumns(mergedColumns);
      }
    } catch (error) {
      console.error("Lỗi khi tải trạng thái hiển thị cột từ localStorage:", error);
      // Nếu có lỗi khi tải, fallback về cấu hình cột ban đầu
      setColumns(initialColumnsConfig);
    }
  }, []);

  /**
   * useEffect để lưu trạng thái hiển thị cột vào localStorage mỗi khi state 'columns' thay đổi.
   */
  useEffect(() => {
    try {
      // Chỉ lưu id và trạng thái hiển thị để tránh lưu trữ các thuộc tính CSS không cần thiết
      const columnsToSave = Object.keys(columns).map(key => ({
        id: key,
        visible: columns[key].visible
      }));
      localStorage.setItem('tableColumnsVisibility_WoodBusiness', JSON.stringify(columnsToSave)); // ĐỔI KEY LOCALSTORAGE
    } catch (error) {
      console.error("Lỗi khi lưu trạng thái hiển thị cột vào localStorage:", error);
    }
  }, [columns]);


  /**
   * useEffect để tải danh sách các cơ sở kinh doanh gỗ từ API khi component được mount
   * hoặc khi các bộ lọc `selectedLoaiCoSoDangKy` hoặc `selectedTrangThai` thay đổi.
   */
  useEffect(() => {
    const fetchWoodBusinesses = async () => { // ĐỔI TÊN HÀM TỪ fetchFarms
      try {
        const params = {};
        // Filter by farmType is always applied
        if (selectedLoaiCoSoDangKy !== '') {
          params.farmType = selectedLoaiCoSoDangKy; // Backend có thể vẫn dùng farmType để lọc
        }
        // Add status filter to params if `selectedTrangThai` is selected
        if (selectedTrangThai !== '') {
          params.trangThai = selectedTrangThai;
        }

        // Gửi yêu cầu GET đến API để lấy danh sách cơ sở kinh doanh gỗ
        // ĐẢM BẢO URL NÀY LÀ ĐÚNG VỚI ENDPOINT CỦA BẠN TRÊN BACKEND VÀ CỔNG LÀ 5000
        const response = await axios.get('http://localhost:10000/api/farms', { // Vẫn dùng /api/farms nếu backend của bạn trả về tất cả và lọc dựa vào farmType
          headers: {
            Authorization: `Bearer ${token}`
          },
          params: params
        });

        const fetchedWoodBusinesses = response.data.docs || []; // ĐỔI TÊN TỪ fetchedFarms
        setWoods(fetchedWoodBusinesses); // CẬP NHẬT STATE woods

        // Trích xuất các giá trị duy nhất cho các bộ lọc từ dữ liệu đã tải
        // CẬP NHẬT CÁC TRƯỜNG ĐỂ LẤY DỮ LIỆU TỪ CƠ SỞ KINH DOANH GỖ
        const provinces = [...new Set(fetchedWoodBusinesses.map(f => f.tinhThanhPho).filter(Boolean))].sort();
        const communes = [...new Set(fetchedWoodBusinesses.map(f => f.xaPhuong).filter(Boolean))].sort();
        // Giả sử selectedSpecies bây giờ là tên lâm sản hoặc loại hình kinh doanh gỗ
        const speciesNames = [...new Set(fetchedWoodBusinesses.flatMap(f => f.loaiDongVatRung ? f.loaiDongVatRung.map(s => s.tenLamSan) : []).filter(Boolean))].sort(); // Giữ lại nếu tenLamSan có trong cơ sở gỗ
        const loaiCoSoDangKy = [...new Set(fetchedWoodBusinesses.map(f => f.loaiCoSoDangKy).filter(Boolean))].sort();
        const nganhNgheKinhDoanhGo = [...new Set(fetchedWoodBusinesses.map(f => f.nganhNgheKinhDoanhGo).filter(Boolean))].sort();
        const trangThai = [...new Set(fetchedWoodBusinesses.map(f => f.trangThai).filter(Boolean))].sort();

        // Cập nhật các state chứa các giá trị duy nhất
        setUniqueProvinces(provinces);
        setUniqueCommunes(communes);
        setUniqueSpecies(speciesNames); // CẬP NHẬT uniqueSpecies
        setUniqueLoaiCoSoDangKy(loaiCoSoDangKy);
        setUniqueNganhNgheKinhDoanhGo(nganhNgheKinhDoanhGo);
        setUniqueTrangThai(trangThai);

      } catch (error) {
        console.error('❌ Lỗi khi lấy danh sách cơ sở kinh doanh gỗ:', error); // CẬP NHẬT THÔNG BÁO LỖI
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
        setWoods([]); // Đảm bảo woods là mảng rỗng khi có lỗi
      }
    };

    if (token) {
      fetchWoodBusinesses();
    } else {
      navigate('/');
    }
  }, [token, navigate, selectedLoaiCoSoDangKy, selectedTrangThai]);

  /**
   * Hàm xử lý xóa một cơ sở kinh doanh gỗ.
   * @param {string} id - ID của cơ sở cần xóa.
   */
  const handleDelete = async (id) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa cơ sở kinh doanh gỗ này?')) { // CẬP NHẬT THÔNG BÁO XÁC NHẬN
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, { // Vẫn dùng /api/farms nếu đây là xoá cơ sở
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setWoods(woods.filter(f => f._id !== id)); // CẬP NHẬT STATE woods
      } catch (error) {
        console.error('Lỗi khi xóa cơ sở kinh doanh gỗ:', error); // CẬP NHẬT THÔNG BÁO LỖI
      }
    }
  };

  /**
   * Hàm xử lý chỉnh sửa thông tin cơ sở kinh doanh gỗ.
   * @param {string} id - ID của cơ sở cần chỉnh sửa.
   */
  const handleEdit = (id) => {
    navigate(`/edit-wood-business/${id}`); // Giả sử bạn có trang /edit-wood-business/:id
  };

  /**
   * Hàm xử lý xem chi tiết cơ sở kinh doanh gỗ (để nhập, xuất gỗ).
   * @param {string} id - ID của cơ sở kinh doanh gỗ để xem chi tiết.
   */
  const handleNavigateToWoodDetail = (id) => { // ĐỔI TÊN HÀM TỪ handleView
    // ĐIỀU CHỈNH ĐƯỜNG DẪN ĐIỀU HƯỚNG TỚI TRANG WoodDetail.js
    // `/admin/woods/${id}` nên trỏ tới WoodDetail.js nơi bạn theo dõi nhập/xuất của cơ sở
    navigate(`/admin/woods/${id}`); // Đảm bảo route này khớp với App.js của bạn
  };

  /**
   * Lọc danh sách cơ sở kinh doanh gỗ dựa trên tất cả các tiêu chí.
   */
  const filteredWoods = woods.filter(f => { // ĐỔI TÊN TỪ filteredFarms
    // Kiểm tra khớp với bộ lọc tìm kiếm chung
    const generalMatch = (
      (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.tinhThanhPho || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.xaPhuong || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.diaChiCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.ghiChu || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.loaiCoSoDangKy || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.nganhNgheKinhDoanhGo || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.khoiLuong && String(f.khoiLuong).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenLamSan && String(f.tenLamSan).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenKhoaHoc && String(f.tenKhoaHoc).toLowerCase().includes(filter.toLowerCase())) ||
      (f.trangThai && String(f.trangThai).toLowerCase().includes(filter.toLowerCase())) ||
      (f.tenNguoiDaiDien || '').toLowerCase().includes(filter.toLowerCase()) ||
      (f.namSinh && String(f.namSinh).toLowerCase().includes(filter.toLowerCase())) ||
      (f.soCCCD && String(f.soCCCD).toLowerCase().includes(filter.toLowerCase())) ||
      (f.ngayCapCCCD && new Date(f.ngayCapCCCD).toLocaleDateString().toLowerCase().includes(filter.toLowerCase())) ||
      (f.noiCapCCCD && String(f.noiCapCCCD).toLowerCase().includes(filter.toLowerCase())) ||
      (f.soDienThoaiNguoiDaiDien && String(f.soDienThoaiNguoiDaiDien).toLowerCase().includes(filter.toLowerCase())) ||
      (f.diaChiNguoiDaiDien && String(f.diaChiNguoiDaiDien).toLowerCase().includes(filter.toLowerCase()))
    );

    // Kiểm tra khớp với bộ lọc Tỉnh (Thành phố)
    const provinceMatch = selectedProvince ? (f.tinhThanhPho === selectedProvince) : true;
    // Kiểm tra khớp với bộ lọc Xã (Phường)
    const communeMatch = selectedCommune ? (f.xaPhuong === selectedCommune) : true;
    // Kiểm tra khớp với bộ lọc Loài (nếu có trường species/tenLamSan)
    // Giả sử selectedSpecies bây giờ là tenLamSan hoặc một loại hình gỗ
    const speciesMatch = selectedSpecies ? (f.loaiDongVatRung && f.loaiDongVatRung.some(s => s.tenLamSan === selectedSpecies)) : true;

    const nganhNgheKinhDoanhGoMatch = selectedNganhNgheKinhDoanhGo ? (f.nganhNgheKinhDoanhGo === selectedNganhNgheKinhDoanhGo) : true;
    const trangThaiMatch = selectedTrangThai ? (f.trangThai === selectedTrangThai) : true;


    // Trả về true nếu tất cả các điều kiện bộ lọc đều khớp
    return generalMatch && provinceMatch && communeMatch && speciesMatch && nganhNgheKinhDoanhGoMatch && trangThaiMatch;
  });

  // Logic phân trang
  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;
  const currentItems = filteredWoods.slice(indexOfFirstItem, indexOfLastItem); // CẬP NHẬT TỪ filteredFarms

  const totalPages = Math.ceil(filteredWoods.length / itemsPerPage); // CẬP NHẬT TỪ filteredFarms

  // Hàm thay đổi trang hiện tại
  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  // Hàm chuyển đến trang tiếp theo
  const nextPage = () => {
    if (currentPage < totalPages) {
      setCurrentPage(currentPage + 1);
    }
  };

  // Hàm chuyển đến trang trước
  const prevPage = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    }
  };

  /**
   * Hàm xử lý việc bật/tắt hiển thị cột.
   * @param {string} columnKey - Khóa của cột cần thay đổi trạng thái hiển thị.
   */
  const handleColumnToggle = (columnKey) => {
    setColumns(prevColumns => ({
      ...prevColumns,
      [columnKey]: {
        ...prevColumns[columnKey],
        visible: !prevColumns[columnKey].visible // Đảo ngược trạng thái hiển thị của cột
      }
    }));
  };

  /**
   * Hàm chọn tất cả các cột hiển thị.
   */
  const handleSelectAllColumns = () => {
    setColumns(prevColumns => {
      const newColumns = { ...prevColumns };
      for (const key in newColumns) {
        newColumns[key].visible = true;
      }
      return newColumns;
    });
  };

  /**
   * Hàm bỏ chọn tất cả các cột hiển thị (trừ cột hành động).
   */
  const handleDeselectAllColumns = () => {
    setColumns(prevColumns => {
      const newColumns = { ...prevColumns };
      for (const key in newColumns) {
        // Luôn giữ cột 'actions' hiển thị
        if (key === 'actions') {
          newColumns[key].visible = true;
        } else {
          newColumns[key].visible = false;
        }
      }
      return newColumns;
    });
  };

  /**
   * Hàm xuất dữ liệu bảng ra file Excel.
   */
  const handleExportExcel = () => {
    // Lọc các cột hiển thị không phải là cột 'actions'
    const columnsToExport = Object.values(columns).filter(col => col.visible && col.id !== 'actions');

    // Chuẩn bị dữ liệu cho Excel
    const dataToExport = filteredWoods.map(item => { // CẬP NHẬT TỪ filteredFarms
      const rowData = {};
      columnsToExport.forEach(col => {
        let value = item[col.id];
        // Xử lý định dạng ngày tháng cho các trường ngày
        if (['ngayThanhLap', 'ngayCapCCCD'].includes(col.id)) {
          value = value ? new Date(value).toLocaleDateString() : '';
        }
        // Xử lý trường loaiDongVatRung nếu cần hiển thị tên lâm sản
        if (col.id === 'loaiDongVatRung' && Array.isArray(value)) {
            value = value.map(s => s.tenLamSan).join(', ');
        }
        rowData[col.label] = value; // Sử dụng nhãn làm tiêu đề cột trong Excel
      });
      return rowData;
    });

    // Tạo worksheet từ JSON
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    // Tạo workbook mới
    const wb = XLSX.utils.book_new();
    // Thêm worksheet vào workbook
    XLSX.utils.book_append_sheet(wb, ws, "DanhSachCoSoKinhDoanhGo"); // CẬP NHẬT TÊN SHEET
    // Xuất file Excel
    XLSX.writeFile(wb, "DanhSachCoSoKinhDoanhGo.xlsx"); // CẬP NHẬT TÊN FILE
  };

  return (
    <div className="farm-list-container"> {/* Container chính cho trang danh sách */}
      <h2>📋 Danh sách cơ sở kinh doanh, chế biến gỗ</h2>

      <div className="filter-container"> {/* Container cho các bộ lọc */}
        <input
          type="text"
          placeholder="🔍 Tìm kiếm chung..."
          value={filter}
          onChange={e => setFilter(e.target.value)}
        />

        {/* Bộ lọc mới cho Loại cơ sở đăng ký - ẨN ĐI (đã được đặt giá trị mặc định) */}
        {/* <select
          value={selectedLoaiCoSoDangKy}
          onChange={e => setSelectedLoaiCoSoDangKy(e.target.value)}
        >
          <option value="">Tất cả cơ sở</option>
          <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
          <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
        </select> */}

        <select
          value={selectedProvince}
          onChange={e => setSelectedProvince(e.target.value)}
        >
          <option value="">Tất cả Tỉnh (TP)</option>
          {uniqueProvinces.map(province => (
            <option key={province} value={province}>{province}</option>
          ))}
        </select>

        <select
          value={selectedCommune}
          onChange={e => setSelectedCommune(e.target.value)}
        >
          <option value="">Tất cả Xã (Phường)</option>
          {uniqueCommunes.map(commune => (
            <option key={commune} value={commune}>{commune}</option>
          ))}
        </select>

        <select
          value={selectedSpecies} // Đây có thể là bộ lọc theo tên lâm sản
          onChange={e => setSelectedSpecies(e.target.value)}
        >
          <option value="">Tất cả Tên lâm sản</option> {/* CẬP NHẬT NHÃN */}
          {uniqueSpecies.map(species => ( // uniqueSpecies giờ chứa tên lâm sản
            <option key={species} value={species}>{species}</option>
          ))}
        </select>

        {/* Bộ lọc mới cho Ngành nghề kinh doanh gỗ */}
        <select
          value={selectedNganhNgheKinhDoanhGo}
          onChange={e => setSelectedNganhNgheKinhDoanhGo(e.target.value)}
        >
          <option value="">Tất cả Ngành nghề KD gỗ</option>
          {uniqueNganhNgheKinhDoanhGo.map(nganhNghe => (
            <option key={nganhNghe} value={nganhNghe}>{nganhNghe}</option>
          ))}
        </select>

        {/* Bộ lọc mới cho Trạng thái */}
        <select
          value={selectedTrangThai}
          onChange={e => setSelectedTrangThai(e.target.value)}
        >
          <option value="">Tất cả Trạng thái</option>
          {uniqueTrangThai.map(status => (
            <option key={status} value={status}>{status}</option>
          ))}
        </select>

        <button
          onClick={() => setShowColumnOptions(!showColumnOptions)}
        >
          {showColumnOptions ? 'Ẩn cột' : 'Hiện, ẩn cột'}
        </button>

        {/* Nút Xuất Excel */}
        <button
          onClick={handleExportExcel}
          className="export-excel-button"
        >
          Xuất Excel
        </button>
      </div>

      {showColumnOptions && (
        <div className="column-options-container">
          <h3>Chọn cột hiển thị:</h3>
          <div className="column-options-grid">
            {Object.keys(columns).map(key => (
              <label key={key}>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  onChange={() => handleColumnToggle(key)}
                />
                {columns[key].label}
              </label>
            ))}
          </div>
          <div className="column-control-buttons">
            <button onClick={handleSelectAllColumns} className="select-all-columns-button">
              Chọn tất cả
            </button>
            <button onClick={handleDeselectAllColumns} className="select-all-columns-button">
              Bỏ chọn tất cả
            </button>
          </div>
        </div>
      )}

      {/* Hiển thị thông báo khi không có cơ sở kinh doanh gỗ nào */}
      {woods.length === 0 && !filter && <p>Không có cơ sở kinh doanh gỗ nào được đăng ký.</p>}
      {woods.length === 0 && filter && <p>Không tìm thấy cơ sở kinh doanh gỗ nào phù hợp với bộ lọc.</p>}

      {/* Bảng hiển thị danh sách cơ sở kinh doanh gỗ nếu có dữ liệu */}
      {filteredWoods.length > 0 && (
        <table border="1" cellPadding="8" className="table-auto w-full border-collapse">
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              {Object.keys(columns).map(key => (
                <th
                  key={key}
                  className={!columns[key].visible ? 'column-hidden' : ''}
                  style={
                    key === 'actions'
                      ? { // Cột hành động: chiều rộng cố định
                          width: columns[key].width,
                          minWidth: columns[key].minWidth,
                          maxWidth: columns[key].maxWidth,
                        }
                      : (columns[key].visible
                          ? { // Các cột không phải hành động đang hiển thị: sử dụng minWidth làm chiều rộng
                              width: columns[key].minWidth, // Đặt chiều rộng bằng minWidth
                              minWidth: columns[key].minWidth, // Đảm bảo minWidth được tôn trọng
                              maxWidth: columns[key].maxWidth || 'auto', // Cho phép mở rộng nếu có không gian, nhưng giữ ellipsis
                            }
                          : {}
                        )
                  }
                >
                  {columns[key].label}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {currentItems.map((item, i) => ( // ĐỔI f THÀNH item để dễ hiểu
              <tr key={item._id || i}>
                {Object.keys(columns).map(key => (
                  <td
                    key={`${item._id || i}-${key}`}
                    className={!columns[key].visible ? 'column-hidden' : ''}
                    style={
                      key === 'actions'
                        ? { // Cột hành động: chiều rộng cố định
                            width: columns[key].width,
                            minWidth: columns[key].minWidth,
                            maxWidth: columns[key].maxWidth,
                          }
                        : (columns[key].visible
                            ? { // Các cột không phải hành động đang hiển thị: sử dụng minWidth làm chiều rộng
                                width: columns[key].minWidth, // Đặt chiều rộng bằng minWidth
                                minWidth: columns[key].minWidth, // Đảm bảo minWidth được tôn trọng
                                maxWidth: columns[key].maxWidth || 'auto', // Cho phép mở rộng nếu có không gian, nhưng giữ ellipsis
                              }
                            : {}
                          )
                    }
                  >
                    {/* Xử lý định dạng cho các trường ngày tháng */}
                    {['ngayThanhLap', 'ngayCapCCCD'].includes(key) ?
                      (item[key] ? new Date(item[key]).toLocaleDateString() : '') :
                      // Xử lý cột 'actions'
                      (key === 'actions' ? (
                        <div className="action-buttons-cell">
                          {/* SỬA ĐIỂM QUAN TRỌNG NÀY: CHUYỂN HƯỚNG ĐẾN WOODDETAIL.JS */}
                          <button onClick={() => handleNavigateToWoodDetail(item._id)} className="action-button view-button">Nhập, xuất</button>{' '}
                          <button onClick={() => handleEdit(item._id)} className="action-button edit-button">✏️</button>{' '}
                          <button onClick={() => handleDelete(item._id)} className="action-button delete-button">🗑️</button>
                        </div>
                      ) : (
                        // Xử lý các trường có thể là mảng lồng nhau, ví dụ 'loaiDongVatRung'
                        key === 'loaiDongVatRung' && Array.isArray(item[key])
                            ? item[key].map(s => s.tenLamSan).filter(Boolean).join(', ')
                            : item[key] // Giá trị mặc định cho các trường khác
                      ))
                    }
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Điều khiển phân trang */}
      {filteredWoods.length > 0 && (
        <div className="pagination-container">
          <div className="pagination-info">
            {indexOfFirstItem + 1} - {Math.min(indexOfLastItem, filteredWoods.length)} / {filteredWoods.length} bản ghi
          </div>
          <div className="pagination-controls">
            <button onClick={prevPage} disabled={currentPage === 1} className="pagination-button">«</button>
            {Array.from({ length: totalPages }, (_, i) => (
              <button
                key={i + 1}
                onClick={() => paginate(i + 1)}
                className={`pagination-button ${currentPage === i + 1 ? 'active' : ''}`}
              >
                {i + 1}
              </button>
            ))}
            <button onClick={nextPage} disabled={currentPage === totalPages} className="pagination-button">»</button>
          </div>
          <div className="items-per-page">
            <select value={itemsPerPage} onChange={(e) => {
              setItemsPerPage(Number(e.target.value));
              setCurrentPage(1); // Đặt lại về trang đầu tiên khi số mục mỗi trang thay đổi
            }}>
              <option value="5">5 bản ghi/trang</option>
              <option value="10">10 bản ghi/trang</option>
              <option value="15">15 bản ghi/trang</option>
              <option value="20">20 bản ghi/trang</option>
              <option value="50">50 bản ghi/trang</option>
            </select>
          </div>
        </div>
      )}
    </div>
  );
}

export default RegisterManageSub1Page; // ĐỔI TÊN COMPONENT Ở EXPORT
